abstract class Handler
{
    protected Handler next;
    public void SetNext(Handler h) => next = h;
    public virtual void Handle(int level)
    {
        if (next != null) next.Handle(level);
    }
}
class InfoHandler : Handler
{
    public override void Handle(int level)
    {
        if (level == 1) Console.Write("Info");
        else base.Handle(level);
    }
}
class ErrorHandler : Handler
{
    public override void Handle(int level)
    {
        if (level == 2) Console.Write("Error");
        else base.Handle(level);
    }
}
var info = new InfoHandler();
var error = new ErrorHandler();
info.SetNext(error);
info.Handle(2);

